import * as React from 'react';

/**
 * A single node in a hierarchical tree structure.
 *
 * @template T - Arbitrary metadata attached to the node (e.g. vuln counts, file sizes)
 */
type TreeNode<T = Record<string, unknown>> = {
    /** Unique identifier for this node. */
    id: string;
    /** Display label shown in the tree row. */
    label: string;
    /** Child nodes — presence determines whether the node is a branch (folder). */
    children?: TreeNode<T>[];
    /** Optional arbitrary metadata (SBOM package info, file size, etc.). */
    data?: T;
};
type BaseTreeViewProps<T = Record<string, unknown>> = {
    /** The root nodes to render. */
    nodes: TreeNode<T>[];
    /**
     * Custom render function for node content. Receives the node and its depth.
     * When omitted, renders a Folder/File icon + label text.
     */
    renderNode?: (node: TreeNode<T>, depth: number) => React.ReactNode;
    /**
     * Node IDs that are expanded on first render (uncontrolled).
     * Ignored when `expanded` is provided.
     */
    defaultExpanded?: string[];
    /** Controlled set of expanded node IDs. */
    expanded?: string[];
    /** Called when the expanded set changes (controlled mode). */
    onExpandedChange?: (ids: string[]) => void;
    /** Additional class names applied to the root ul element. */
    className?: string;
};
/**
 * Props for TreeView. The multiSelect flag changes the shape of selected
 * and onSelect to enforce type-safe single vs. multi-select usage.
 */
type TreeViewProps<T = Record<string, unknown>> = BaseTreeViewProps<T> & ({
    /** Single-select mode (default). */
    multiSelect?: false;
    /** Controlled selected node ID. */
    selected?: string;
    /** Called when a node is selected. */
    onSelect?: (id: string, node: TreeNode<T>) => void;
} | {
    /** Multi-select mode. Ctrl+click toggles; Shift+click range-selects. */
    multiSelect: true;
    /** Controlled set of selected node IDs. */
    selected?: string[];
    /** Called when the selection set changes. */
    onSelect?: (ids: string[]) => void;
});
type SelectEventMeta = {
    /** True when Ctrl or Meta (Cmd) was held. */
    ctrlKey: boolean;
    /** True when Shift was held. */
    shiftKey: boolean;
};
type TreeViewNodeProps<T = Record<string, unknown>> = {
    node: TreeNode<T>;
    depth: number;
    expandedIds: Set<string>;
    /** All currently selected IDs — works for both single and multi-select. */
    selectedIds: Set<string>;
    focusedId: string | undefined;
    onToggle: (id: string) => void;
    onSelect: (id: string, node: TreeNode<T>, meta: SelectEventMeta) => void;
    onKeyDown: (e: React.KeyboardEvent, id: string, node: TreeNode<T>, hasChildren: boolean, isExpanded: boolean) => void;
    renderNode?: (node: TreeNode<T>, depth: number) => React.ReactNode;
    setRef: (id: string, el: HTMLLIElement | null) => void;
};

export type { SelectEventMeta, TreeNode, TreeViewNodeProps, TreeViewProps };
